export function parseArgs(argv) {
  const result = { _: [] }
  let i = 0
  while (i < argv.length) {
    const arg = argv[i]
    if (!arg.startsWith('-')) {
      result._.push(arg)
      i++
      continue
    }
    if (arg.startsWith('--')) {
      if (arg.includes('=')) {
        const [key, value] = arg.split('=', 2)
        result[key] = value
        i++
        continue
      }
      if (i + 1 < argv.length && !argv[i + 1].startsWith('-')) {
        result[arg.slice(2)] = argv[i + 1]
        i += 2
        continue
      }
      result[arg.slice(2)] = true
      i++
    } else {
      if (i + 1 < argv.length) {
        result[arg.slice(1)] = argv[i + 1]
        i += 2
        continue
      }
      result[arg.slice(1)] = true
      i++
    }
  }
  return result
}

